//! Critical tests for stdout/stderr stream separation.
//!
//! These tests ensure that stdout ONLY contains JSON and stderr
//! is used for all human-readable output.

use std::process::{Command, Stdio};
use std::io::Write;
use tracing::{info, error};

/// Test that stdout contains ONLY valid JSON (no prose, no ANSI)
#[test]
fn test_stdout_is_pure_json_hook_mode() {
    let output = run_hook_mode("rm -rf /");

    // stdout must be valid JSON
    let json_result: Result<serde_json::Value, _> = serde_json::from_str(&output.stdout);
    assert!(
        json_result.is_ok(),
        "CRITICAL: Hook mode stdout must be valid JSON\nGot: {}",
        output.stdout
    );

    // stdout must NOT contain ANSI escape codes
    assert!(
        !output.stdout.contains("\x1b["),
        "CRITICAL: stdout contains ANSI codes - this breaks agent parsing\n{}",
        output.stdout
    );

    // stdout must NOT contain rich_rust markup
    assert!(
        !output.stdout.contains("[bold]"),
        "CRITICAL: stdout contains rich_rust markup - this breaks parsing"
    );

    // stdout must NOT contain emoji (unless in JSON string values)
    let json = json_result.unwrap();
    let raw_stdout_no_strings = strip_json_string_values(&output.stdout);
    assert!(
        !contains_emoji(&raw_stdout_no_strings),
        "CRITICAL: stdout contains emoji outside JSON strings"
    );
}

/// Test that stdout is EMPTY for allowed commands (hook mode)
#[test]
fn test_stdout_empty_for_allowed_hook_mode() {
    let output = run_hook_mode("echo hello");

    assert!(
        output.stdout.trim().is_empty(),
