```rust
//! Theme mapping between ratatui colors and rich_rust styles.

use ratatui::style::Color as RatatuiColor;
use crate::output::theme::{Theme, Severity};

#[cfg(feature = "rich-output")]
use rich_rust::prelude::*;

/// Extension trait for Theme to get rich_rust styles.
pub trait RichThemeExt {
    fn rich_severity_style(&self, severity: Severity) -> Style;
    fn rich_color(&self, color: RatatuiColor) -> &'static str;
}

#[cfg(feature = "rich-output")]
impl RichThemeExt for Theme {
    fn rich_severity_style(&self, severity: Severity) -> Style {
        match severity {
            Severity::Critical => Style::new().bold().color("bright_red"),
            Severity::High => Style::new().color("red"),
            Severity::Medium => Style::new().color("yellow"),
            Severity::Low => Style::new().color("blue"),
        }
    }

    fn rich_color(&self, color: RatatuiColor) -> &'static str {
        match color {
            RatatuiColor::Red => "red",
            RatatuiColor::Green => "green",
            RatatuiColor::Yellow => "yellow",
            RatatuiColor::Blue => "blue",
            RatatuiColor::Magenta => "magenta",
            RatatuiColor::Cyan => "cyan",
            RatatuiColor::White => "white",
            RatatuiColor::Black => "black",
            RatatuiColor::LightRed => "bright_red",
            RatatuiColor::LightGreen => "bright_green",
            // ... etc
            _ => "default",
        }
    }
}

/// Map severity to appropriate BoxStyle.
pub fn severity_to_box_style(severity: Severity) -> BoxStyle {
    match severity {
        Severity::Critical => BoxStyle::double(),
        Severity::High => BoxStyle::heavy(),
        Severity::Medium => BoxStyle::rounded(),
        Severity::Low => BoxStyle::simple(),
    }
}
```

### Usage

```rust
use crate::output::rich_theme::RichThemeExt;

let theme = Theme::default();
let border_style = theme.rich_severity_style(Severity::Critical);
let box_style = severity_to_box_style(Severity::Critical);
```

